const Header = ({props}) => {

  return(

      <h1>{props}</h1>


  )

}

const Parts = (props) => {
  return(
    <>
      <p>{props.part.name}</p>
      <p>{props.part.exercise}</p>


    </>

  );

}

const Content =(props) => {
  return(
  <>

    <Parts part = {props.parts[0]} />
    <Parts part = {props.parts[1]} />
    <Parts part = {props.parts[2]} />

</>
  );

}

const Total =(props) => {
  let Total =  props.parts[0].exercise + props.parts[1].exercise + props.parts[2].exercise;
  return(
    <p>Number of excercises: {Total}</p>

  );

}


const App = () => {
  const course = {
    name:  'Half Stack application development',
    parts: [
      {name: 'Fundamentals of React',
      exercise: 10},
      {name:'Using props to pass data',
      exercise: 7},
      {name: 'State of a component',
      exercise: 14}

    ]
  }

  return (
    <>
       <Header a={course.name} />

       <Content parts = {course.parts} 
      />

      <Total parts = {course.parts}
       />
    </>
  )
}

export default App
